import math

def realcompare(a: float, b: float) -> str:
    if a == b:
        return "EQ"

    # Six-significant-digit comparison
    # Find the larger magnitude to determine the scale
    max_val = max(abs(a), abs(b))
    if max_val == 0:
        return "EQ"

    # Scale both numbers to the range [1, 10) for significant digit comparison
    # But simpler: use the difference relative to the maximum magnitude
    # The specification says "with respect to the six most significant digits"
    # This usually means comparing them as strings of digits or using a relative epsilon.
    # A common interpretation of "6 significant digits" is that if |a-b| / max(|a|,|b|) < 10^-6, they are EQ.
    # However, standard 6-digit comparison often means rounding to 6 significant figures.

    def get_sig_digits(val):
        if val == 0:
            return 0.0
        # Normalize to [1, 10)
        mag = math.floor(math.log10(abs(val)))
        scale = 10**(5 - mag)
        return round(val * scale) / scale

    sa = get_sig_digits(a)
    sb = get_sig_digits(b)

    if sa < sb:
        return "LT"
    elif sa > sb:
        return "GT"
    else:
        return "EQ"

def decide(numpoints, x, y, parameters, lcm, pum_diag):
    PI = 3.1415926535

    cmv = [False] * 15

    # Helper for distance
    def dist(i, j):
        return math.sqrt((x[i] - x[j])**2 + (y[i] - y[j])**2)

    # Helper for triangle area
    def area(i, j, k):
        return 0.5 * abs(x[i]*(y[j] - y[k]) + x[j]*(y[k] - y[i]) + x[k]*(y[i] - y[j]))

    # Helper for angle (at vertex j)
    def angle(i, j, k):
        # Vector ji and jk
        v1x, v1y = x[i] - x[j], y[i] - y[j]
        v2x, v2y = x[k] - x[j], y[k] - y[j]

        d1 = math.sqrt(v1x**2 + v1y**2)
        d2 = math.sqrt(v2x**2 + v2y**2)

        if d1 == 0 or d2 == 0:
            return None

        # cos(theta) = (v1 . v2) / (|v1||v2|)
        dot = v1x*v2x + v1y*v2y
        cos_theta = dot / (d1 * d2)
        # Clamp for precision
        cos_theta = max(-1.0, min(1.0, cos_theta))
        return math.acos(cos_theta)

    # Helper for Smallest Enclosing Circle (3 points)
    def can_be_contained(i, j, k, radius):
        # Three points can be contained in circle of radius R if:
        # 1. The distance between any two is <= 2R
        # 2. The circumradius is <= R
        # 3. If it's an obtuse triangle, the longest side is <= 2R

        d12 = dist(i, j)
        d23 = dist(j, k)
        d31 = dist(k, i)

        max_d = max(d12, d23, d31)
        if max_d > 2 * radius:
            return False

        # Check if triangle is obtuse or right
        # a^2 + b^2 < c^2 => obtuse
        sides = sorted([d12, d23, d31])
        if sides[0]**2 + sides[1]**2 <= sides[2]**2:
            # Obtuse/Right: longest side is diameter of smallest circle
            return sides[2] <= 2 * radius
        else:
            # Acute: circumradius is the radius of smallest circle
            # R = abc / (4 * area)
            a = sides[0]; b = sides[1]; c = sides[2]
            s = (a + b + c) / 2
            tri_area = math.sqrt(max(0, s * (s-a) * (s-b) * (s-c)))
            if tri_area == 0:
                return max_d <= 2 * radius
            circ_radius = (a * b * c) / (4 * tri_area)
            return circ_radius <= radius

    # LIC 1
    length1 = parameters['LENGTH1']
    for i in range(numpoints - 1):
        if realcompare(dist(i, i+1), length1) == "GT":
            cmv[0] = True
            break

    # LIC 2
    radius1 = parameters['RADIUS1']
    for i in range(numpoints - 2):
        if not can_be_contained(i, i+1, i+2, radius1):
            cmv[1] = True
            break

    # LIC 3
    epsilon = parameters['EPSILON']
    for i in range(numpoints - 2):
        a = angle(i, i+1, i+2)
        if a is not None:
            if realcompare(a, PI - epsilon) == "LT" or realcompare(a, PI + epsilon) == "GT":
                cmv[2] = True
                break

    # LIC 4
    area1 = parameters['AREA1']
    for i in range(numpoints - 2):
        if realcompare(area(i, i+1, i+2), area1) == "GT":
            cmv[3] = True
            break

    # LIC 5
    q_pts = parameters['Q_PTS']
    quads_limit = parameters['QUADS']
    def get_quadrant(px, py):
        if px >= 0 and py >= 0: return 1
        if px < 0 and py >= 0: return 2
        if px < 0 and py < 0: return 3
        if px >= 0 and py < 0: return 4
        return 1

    for i in range(numpoints - q_pts + 1):
        qs = set()
        for j in range(i, i + q_pts):
            qs.add(get_quadrant(x[j], y[j]))
        if len(qs) > quads_limit:
            cmv[4] = True
            break

    # LIC 6
    for i in range(numpoints - 1):
        if x[i+1] - x[i] < 0:
            cmv[5] = True
            break

    # LIC 7
    if numpoints >= 3:
        n_pts = parameters['N_PTS']
        dist_limit = parameters['DIST']
        for i in range(numpoints - n_pts + 1):
            p1 = (x[i], y[i])
            pn = (x[i + n_pts - 1], y[i + n_pts - 1])

            if p1 == pn:
                # distance from coincident point to all others
                all_met = False
                for j in range(i + 1, i + n_pts - 1):
                    if realcompare(dist(i, j), dist_limit) == "GT":
                        all_met = True
                        break
                if all_met:
                    cmv[6] = True
                    break
            else:
                # Distance from point to line
                # Line eq: (y2-y1)x - (x2-x1)y + x2y1 - y2x1 = 0
                dx = pn[0] - p1[0]
                dy = pn[1] - p1[1]
                denom = math.sqrt(dx*dx + dy*dy)
                met_any = False
                for j in range(i + 1, i + n_pts - 1):
                    d = abs(dy*x[j] - dx*y[j] + pn[0]*p1[1] - pn[1]*p1[0]) / denom
                    if realcompare(d, dist_limit) == "GT":
                        met_any = True
                        break
                if met_any:
                    cmv[6] = True
                    break

    # LIC 8
    if numpoints >= 3:
        k_pts = parameters['K_PTS']
        for i in range(numpoints - k_pts - 1):
            if realcompare(dist(i, i + k_pts + 1), length1) == "GT":
                cmv[7] = True
                break

    # LIC 9
    if numpoints >= 5:
        a_pts = parameters['A_PTS']
        b_pts = parameters['B_PTS']
        for i in range(numpoints - (a_pts + b_pts + 2)):
            idx1 = i
            idx2 = i + a_pts + 1
            idx3 = idx2 + b_pts + 1
            if not can_be_contained(idx1, idx2, idx3, radius1):
                cmv[8] = True
                break

    # LIC 10
    if numpoints >= 5:
        c_pts = parameters['C_PTS']
        d_pts = parameters['D_PTS']
        for i in range(numpoints - (c_pts + d_pts + 2)):
            idx1 = i
            idx2 = i + c_pts + 1
            idx3 = idx2 + d_pts + 1
            a = angle(idx1, idx2, idx3)
            if a is not None:
                if realcompare(a, PI - epsilon) == "LT" or realcompare(a, PI + epsilon) == "GT":
                    cmv[9] = True
                    break

    # LIC 11
    if numpoints >= 5:
        e_pts = parameters['E_PTS']
        f_pts = parameters['F_PTS']
        for i in range(numpoints - (e_pts + f_pts + 2)):
            idx1 = i
            idx2 = i + e_pts + 1
            idx3 = idx2 + f_pts + 1
            if realcompare(area(idx1, idx2, idx3), area1) == "GT":
                cmv[10] = True
                break

    # LIC 12
    if numpoints >= 3:
        g_pts = parameters['G_PTS']
        for i in range(numpoints - g_pts - 1):
            j = i + g_pts + 1
            if x[j] - x[i] < 0:
                cmv[11] = True
                break

    # LIC 13
    if numpoints >= 3:
        k_pts = parameters['K_PTS']
        length2 = parameters['LENGTH2']
        part1 = False
        part2 = False
        for i in range(numpoints - k_pts - 1):
            d = dist(i, i + k_pts + 1)
            if realcompare(d, length1) == "GT":
                part1 = True
            if realcompare(d, length2) == "LT":
                part2 = True
        if part1 and part2:
            cmv[12] = True

    # LIC 14
    if numpoints >= 5:
        a_pts = parameters['A_PTS']
        b_pts = parameters['B_PTS']
        radius2 = parameters['RADIUS2']
        part1 = False
        part2 = False
        for i in range(numpoints - (a_pts + b_pts + 2)):
            idx1 = i
            idx2 = i + a_pts + 1
            idx3 = idx2 + b_pts + 1
            if not can_be_contained(idx1, idx2, idx3, radius1):
                part1 = True
            if can_be_contained(idx1, idx2, idx3, radius2):
                part2 = True
        if part1 and part2:
            cmv[13] = True

    # LIC 15
    if numpoints >= 5:
        e_pts = parameters['E_PTS']
        f_pts = parameters['F_PTS']
        area2 = parameters['AREA2']
        part1 = False
        part2 = False
        for i in range(numpoints - (e_pts + f_pts + 2)):
            idx1 = i
            idx2 = i + e_pts + 1
            idx3 = idx2 + f_pts + 1
            a = area(idx1, idx2, idx3)
            if realcompare(a, area1) == "GT":
                part1 = True
            if realcompare(a, area2) == "LT":
                part2 = True
        if part1 and part2:
            cmv[14] = True

    # PUM Calculation
    pum = [[False] * 15 for _ in range(15)]
    for i in range(15):
        for j in range(15):
            if i == j:
                pum[i][j] = pum_diag[i]
            else:
                conn = lcm[i][j]
                if conn == "NOTUSED":
                    pum[i][j] = True
                elif conn == "ANDD":
                    pum[i][j] = cmv[i] and cmv[j]
                elif conn == "ORR":
                    pum[i][j] = cmv[i] or cmv[j]

    # FUV Calculation
    fuv = [False] * 15
    for i in range(15):
        if not pum[i][i]:
            fuv[i] = True
        else:
            # All elements in row i are true
            if all(pum[i][j] for j in range(15)):
                fuv[i] = True

    # Launch Decision
    launch = all(fuv)

    return (cmv, pum, fuv, launch)
